import kotlinx.datetime.*
import kotlin.test.*

class InstantParseReproductionTest {
    @Test
    fun testParseWithoutSecondsFails() {
        // "2024-03-19T17:50Z" omits seconds.
        // It should fail with DateTimeFormatException

        try {
            Instant.parse("2024-03-19T17:50Z")
            fail("Instant.parse should fail when seconds are omitted")
        } catch (e: DateTimeFormatException) {
            // Expected
        }
    }

    @Test
    fun testParseWithSecondsSucceeds() {
        // "2024-03-19T17:50:00Z" includes seconds.
        val instant = Instant.parse("2024-03-19T17:50:00Z")
        assertNotNull(instant)
    }
}
