200→public actual fun Instant.until(other: Instant, unit: DateTimeUnit, timeZone: TimeZone): Long = try {
201→    val thisZdt = this.atZone(timeZone)
202→    val otherZdt = other.atZone(timeZone)
203→    when(unit) {
204→        is DateTimeUnit.TimeBased -> until(other, unit)
205→        is DateTimeUnit.DayBased -> (thisZdt.until(otherZdt, jtChronoUnit.DAYS) / unit.days).toLong()
206→        is DateTimeUnit.MonthBased -> (thisZdt.until(otherZdt, jtChronoUnit.MONTHS) / unit.months).toLong()
207→    }
208→} catch (e: ArithmeticException) {
209→    if (this < other) Long.MAX_VALUE else Long.MIN_VALUE
210→} catch (e: Throwable) {
211→    if (e.isJodaDateTimeException()) throw DateTimeArithmeticException(e) else throw e
